The subject spec JSON file (e.g., subjects/chemistryinstructor.json) defines the NPC persona, research queries, and dataset structure:

json
{
  "npckey": "chemistryinstructor",
  "npcname": "ChemistryInstructor",
  "subject": "General chemistry: atoms, molecules, elements...",
  "systemprompt": "You are ChemistryInstructor... Rules: 1-3 sentences...",
  "research": [
    {
      "query": "General chemistry basics atoms molecules periodic table...",
      "mode": "fast",
      "from": "web",
      "sourcepolicy": "text-web"
    }
  ],
  "dataset": {
    "examplespercategory": {
      "identity": 8,
      "teaching": 32,
      "dialogue": 16,
      "quest": 8,
      "refusal": 8
    }
  }
}

